namespace NotificationsApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 4;
    private readonly Lock _lock = new();

    // Simulates an initial batch of notifications.
    public Task<List<Notification>> GetInitialNotificationsAsync()
    {
        var notifications = new List<Notification>
        {
            new(1, "Welcome to the app!", DateTime.UtcNow.AddMinutes(-10)),
            new(2, "Your profile was updated.", DateTime.UtcNow.AddMinutes(-5)),
            new(3, "New feature available: Dark Mode.", DateTime.UtcNow.AddMinutes(-1)),
        };
        return Task.FromResult(notifications);
    }

    // Simulates checking for new notifications since a given ID.
    // Randomly produces 0-1 new notifications per call.
    public Task<List<Notification>> GetNewNotificationsSinceAsync(int lastId)
    {
        var results = new List<Notification>();

        if (Random.Shared.Next(3) == 0) // ~33% chance of a new notification
        {
            lock (_lock)
            {
                results.Add(new Notification(
                    _nextId++,
                    $"New event at {DateTime.UtcNow:T}",
                    DateTime.UtcNow));
            }
        }

        return Task.FromResult(results);
    }
}

@page "/notifications"
@rendermode InteractiveServer
@using NotificationsApp.Services
@inject NotificationService NotificationService
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h1>Notifications <span class="badge bg-primary">@_notifications.Count</span></h1>

@if (_notifications.Count == 0)
{
    <p><em>No notifications.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in _notifications.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item">
                <strong>@n.Message</strong>
                <small class="text-muted ms-2">@n.Timestamp.ToString("g")</small>
            </li>
        }
    </ul>
}

@code {
    private List<Notification> _notifications = new();
    private CancellationTokenSource? _cts;
    private int _lastId;

    // Runs during SSR — provides initial data in the server-rendered HTML.
    protected override async Task OnInitializedAsync()
    {
        _notifications = await NotificationService.GetInitialNotificationsAsync();
        _lastId = _notifications.Count > 0 ? _notifications.Max(n => n.Id) : 0;
    }

    // Only fires once the component is interactive in the browser — never during static SSR.
    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), ct);

            var newItems = await NotificationService.GetNewNotificationsSinceAsync(_lastId);
            if (newItems.Count > 0)
            {
                _notifications.AddRange(newItems);
                _lastId = newItems.Max(n => n.Id);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

